#!/usr/bin/env node
// === LS Method Whitelist Generator ===
//
// Emits src/ls-method-whitelist.js — the allowlist for the generic LS proxy
// (POST /api/ls/:method). Two blocks:
//   - SAFE_LS_METHODS    : AUTO-generated — every method the safety classifier
//                          marks read-only. Re-run after each Antigravity update
//                          to pick up new safe methods (the "supplement" step).
//   - MANUAL_MUTATING    : HAND-maintained below — the small set of mutating
//                          methods the Deck intentionally exposes via the proxy.
//                          Never auto-expanded (security gate stays human-owned).
//
//   node tools/api-tracker/gen-whitelist.js

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..', '..');
const REGISTRY = path.join(__dirname, 'schema', 'rpc-registry.json');
const OUT = path.join(ROOT, 'src', 'ls-method-whitelist.js');
const { classifyMethod } = require('./test/lib/safety');

// Hand-curated mutating methods the Deck legitimately drives through the proxy.
// (Internal-only mutators like AcceptDiff/RejectDiff are called directly in code,
// NOT exposed here.) Edit this list by hand; the generator preserves it verbatim.
const MANUAL_MUTATING = [
    'StartCascade',                  // was the misnamed "StartCascadeInvocation"
    'SendUserCascadeMessage',        // was the misnamed "SendCascadeMessage"
    'HandleCascadeUserInteraction',
    'CancelCascadeInvocation',
    'DeleteCascadeTrajectory',
    'InstallCascadePlugin',
    'DeletePlugin',
    'ToggleMcpServer',
    'CopyBuiltinWorkflowToWorkspace',
];

function main() {
    const reg = JSON.parse(fs.readFileSync(REGISTRY, 'utf-8'));
    const svc = reg.find((s) => s.fqService === 'exa.language_server_pb.LanguageServerService');
    if (!svc) { console.error('LanguageServerService not in registry'); process.exit(1); }

    // Read-only but sensitive — withheld from the proxy even though the
    // classifier marks them safe (read-only != safe-to-expose). An authed but
    // untrusted caller must not be able to read arbitrary files, exfiltrate PII,
    // probe auth, or invoke the paid model through the generic proxy.
    const SENSITIVE_EXCLUDE = new Set([
        'GetTokenBase',                                              // raw auth token
        'GetAuthStatus', 'GetGrantedScopes',                        // auth / scope probing
        'FetchUserInfo', 'GetLocalUserInfo', 'GetUserMemories',     // account PII
        'GetCascadeMemories', 'GetUserAnalyticsSummary',
        'ReadFile', 'ReadDir', 'ReadProject', 'SearchCode',         // arbitrary local fs / source read
        'GetDebugDiagnostics', 'GetSidecarLogs', 'CheckDevToolsActivePort', // debug / internal surface
        'GetModelResponse',                                         // invokes the paid model
    ]);
    // NOTE on dropped legacy entries: the old hand-written whitelist had
    // GetSettings / GetWorkspaceFolders (now 404 on the LS — removed by Antigravity),
    // and the MISNAMED StartCascadeInvocation / SendCascadeMessage (real names are
    // StartCascade / SendUserCascadeMessage, present in MANUAL_MUTATING below).
    // UpdateSettings was a local-Deck op, never a real LS method. All intentionally dropped.

    const safe = svc.methods
        .map((m) => m.name)
        .filter((n) => classifyMethod(n).safety === 'safe' && !SENSITIVE_EXCLUDE.has(n))
        .sort();

    const fmt = (arr) => arr.map((n) => `    '${n}',`).join('\n');
    const out = `// === AUTO-GENERATED whitelist for the generic LS proxy (POST /api/ls/:method) ===
// Generated by tools/api-tracker/gen-whitelist.js from the extracted RPC registry.
// SAFE block is auto-generated (read-only methods). MUTATING block is hand-curated
// in the generator. Re-generate after each Antigravity update to add new safe reads.

// Read-only methods — safe to expose via the authenticated proxy.
const SAFE_LS_METHODS = [
${fmt(safe)}
];

// Mutating methods intentionally exposed via the proxy (hand-curated).
const MANUAL_MUTATING_LS_METHODS = [
${fmt(MANUAL_MUTATING)}
];

const ALLOWED_LS_METHODS = new Set([...SAFE_LS_METHODS, ...MANUAL_MUTATING_LS_METHODS]);

module.exports = { ALLOWED_LS_METHODS, SAFE_LS_METHODS, MANUAL_MUTATING_LS_METHODS };
`;
    fs.writeFileSync(OUT, out, 'utf-8');
    console.log(`✅ Generated ${path.relative(ROOT, OUT)}`);
    console.log(`   safe: ${safe.length}, manual-mutating: ${MANUAL_MUTATING.length}, total: ${safe.length + MANUAL_MUTATING.length}`);
}

main();
